package com.example.enterprise.service;

import com.example.enterprise.domain.UserAccount;
import com.example.enterprise.domain.UserStatus;
import com.example.enterprise.repository.UserAccountRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;
import java.util.UUID;

@Service
public class UserAccountService {

    private final UserAccountRepository userAccountRepository;

    public UserAccountService(UserAccountRepository userAccountRepository) {
        this.userAccountRepository = userAccountRepository;
    }

    @Transactional
    public UserAccount createUser(String username, String email) {
        if (userAccountRepository.existsByUsernameIgnoreCase(username)) {
            throw new DataIntegrityViolationException("Username already exists");
        }
        if (userAccountRepository.existsByEmailIgnoreCase(email)) {
            throw new DataIntegrityViolationException("Email already exists");
        }

        UserAccount user = new UserAccount();
        user.setUsername(username);
        user.setEmail(email);
        user.setStatus(UserStatus.ACTIVE);
        return userAccountRepository.save(user);
    }

    @Transactional(readOnly = true)
    public UserAccount getUser(UUID userId) {
        return userAccountRepository.findById(userId).orElseThrow(() -> new EntityNotFoundException("User not found"));
    }

    @Transactional
    public UserAccount disableUser(UUID userId) {
        UserAccount user = getUser(userId);
        user.setStatus(UserStatus.DISABLED);
        return userAccountRepository.save(user);
    }

    @Transactional(readOnly = true)
    public Optional<UserAccount> findByEmail(String email) {
        return userAccountRepository.findByEmailIgnoreCase(email);
    }
}

