package com.example.enterprise.service;

import com.example.enterprise.domain.*;
import com.example.enterprise.repository.AccountTransactionRepository;
import com.example.enterprise.repository.UserAccountRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.UUID;

@Service
public class TransactionService {

    private final AccountTransactionRepository transactionRepository;
    private final UserAccountRepository userAccountRepository;

    public TransactionService(AccountTransactionRepository transactionRepository,
                              UserAccountRepository userAccountRepository) {
        this.transactionRepository = transactionRepository;
        this.userAccountRepository = userAccountRepository;
    }

    @Transactional
    public AccountTransaction createTransaction(UUID userId,
                                                String externalRef,
                                                TransactionType type,
                                                BigDecimal amount,
                                                String currency,
                                                String description) {
        if (transactionRepository.existsByExternalRef(externalRef)) {
            throw new DataIntegrityViolationException("externalRef already exists");
        }

        UserAccount user = userAccountRepository.findById(userId)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        if (user.getStatus() != UserStatus.ACTIVE) {
            throw new IllegalStateException("User is not active");
        }

        AccountTransaction tx = new AccountTransaction();
        tx.setUser(user);
        tx.setExternalRef(externalRef);
        tx.setType(type);
        tx.setAmount(amount);
        tx.setCurrency(currency);
        tx.setDescription(description);
        tx.setStatus(TransactionStatus.PENDING);

        return transactionRepository.save(tx);
    }

    @Transactional
    public AccountTransaction postTransaction(UUID transactionId) {
        AccountTransaction tx = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found"));
        tx.setStatus(TransactionStatus.POSTED);
        return transactionRepository.save(tx);
    }

    @Transactional
    public AccountTransaction failTransaction(UUID transactionId) {
        AccountTransaction tx = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found"));
        tx.setStatus(TransactionStatus.FAILED);
        return transactionRepository.save(tx);
    }
}

