package com.example.enterprise.api;

import com.example.enterprise.api.dto.CreateUserRequest;
import com.example.enterprise.domain.UserAccount;
import com.example.enterprise.service.UserAccountService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.util.UUID;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserAccountService userAccountService;

    public UserController(UserAccountService userAccountService) {
        this.userAccountService = userAccountService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public UserAccount create(@Valid @RequestBody CreateUserRequest request) {
        return userAccountService.createUser(request.getUsername(), request.getEmail());
    }

    @GetMapping("/{id}")
    public UserAccount get(@PathVariable("id") UUID id) {
        return userAccountService.getUser(id);
    }

    @PostMapping("/{id}/disable")
    public UserAccount disable(@PathVariable("id") UUID id) {
        return userAccountService.disableUser(id);
    }
}

